// Sentence-pattern cloze exercises: a sentence with a blank where a connective
// (sentence-structure word) belongs. The learner reads the sentence + its
// translation and picks the connective that fits. Teaches 因為/所以, 如果/就,
// 雖然/但是, 不但/而且, 只要, 即使, 否則, 為了 … in real context.
//
// Each item: before + [blank] + after  (Chinese), with the correct connective
// `answer` and `distractors` (each {zh,py,en,fr}); `full` is the whole sentence
// for audio; `gloss` is the translation shown as the clue.
const C = {
  suoyi: { zh: '所以', py: 'suǒyǐ', en: 'so / therefore', fr: 'donc' },
  danshi: { zh: '但是', py: 'dànshì', en: 'but', fr: 'mais' },
  yinwei: { zh: '因為', py: 'yīnwèi', en: 'because', fr: 'parce que' },
  ruguo: { zh: '如果', py: 'rúguǒ', en: 'if', fr: 'si' },
  suiran: { zh: '雖然', py: 'suīrán', en: 'although', fr: 'bien que' },
  erqie: { zh: '而且', py: 'érqiě', en: 'moreover / and', fr: 'de plus' },
  ranhou: { zh: '然後', py: 'ránhòu', en: 'then / after that', fr: 'ensuite' },
  budan: { zh: '不但', py: 'búdàn', en: 'not only', fr: 'non seulement' },
  zhiyao: { zh: '只要', py: 'zhǐyào', en: 'as long as', fr: 'du moment que' },
  jishi: { zh: '即使', py: 'jíshǐ', en: 'even if', fr: 'même si' },
  fouze: { zh: '否則', py: 'fǒuzé', en: 'otherwise', fr: 'sinon' },
  weile: { zh: '為了', py: 'wèile', en: 'in order to', fr: 'afin de' },
  haishi: { zh: '還是', py: 'háishì', en: 'or (in questions)', fr: 'ou (question)' },
  huozhe: { zh: '或者', py: 'huòzhě', en: 'or', fr: 'ou' },
  buguo: { zh: '不過', py: 'búguò', en: 'however', fr: 'cependant' },
  yinci: { zh: '因此', py: 'yīncǐ', en: 'therefore', fr: 'par conséquent' },
  jiran: { zh: '既然', py: 'jìrán', en: 'since', fr: 'puisque' },
  wulun: { zh: '無論', py: 'wúlùn', en: 'no matter', fr: 'peu importe' },
  chufei: { zh: '除非', py: 'chúfēi', en: 'unless', fr: 'à moins que' },
  yushi: { zh: '於是', py: 'yúshì', en: 'thereupon', fr: 'alors' },
  raner: { zh: '然而', py: 'ránér', en: 'yet / however', fr: 'pourtant' },
  bingqie: { zh: '並且', py: 'bìngqiě', en: 'and / besides', fr: 'et de plus' },
  buguan: { zh: '不管', py: 'bùguǎn', en: 'regardless', fr: 'quel que soit' },
  zhiyou: { zh: '只有', py: 'zhǐyǒu', en: 'only (if)', fr: 'seulement si' },
};

// fullPy = pinyin of the whole sentence (syllables space-separated, no
// punctuation) — used to show the sentence reading and derive its zhuyin.
const P = (id, before, after, answer, distractors, full, fullPy, en, fr) => ({
  id, before, after, answer, distractors, full, fullPy, gloss: { en, fr },
});

