// Word-by-word breakdown of an item's full sentence: [{char, py, en, fr}].
// Returns [] when no glosses are recorded for the item.
export function wordsFor(item) {
  return PATTERN_WORDS[item.id] || [];
}

const isHan = (c) => /[㐀-鿿豈-﫿]/.test(c);

// Split before / answer / after into per-character segments {c, py}, consuming
// the sentence's syllables (fullPy) in order. Punctuation gets an empty py.
// Lets the screen render ruby (reading aligned under each character) and keep
// the answer's reading hidden until it's solved.
export function segmentPattern(item) {
  const syl = item.fullPy.split(/\s+/).filter(Boolean);
  let i = 0;
  const seg = (str) => [...str].map((c) => (isHan(c) ? { c, py: syl[i++] || '' } : { c, py: '' }));
  return { before: seg(item.before), answer: seg(item.answer.zh), after: seg(item.after) };
}

export function optionsFor(item, rand = Math.random) {
  const all = [item.answer, ...item.distractors];
  for (let i = all.length - 1; i > 0; i--) {
    const j = Math.floor(rand() * (i + 1));
    [all[i], all[j]] = [all[j], all[i]];
  }
  return all;
}
